// stdin으로 JSON 받아서 n6_match + mk2 classify → discovery_log 기록
// 사용: echo '$INPUT' | hexa hook.hexa post-edit

// log_path는 _shared 계산 후 런타임에 설정 (타 프로젝트 CWD 대응)

pure fn abs_f(x: float) -> float {
    if x < 0.0 { 0.0 - x } else { x }
}

// ─── n6 상수 동적 로드 (shared/n6_constants.jsonl + n6_physics.jsonl) ───
fn load_jsonl(path: string) -> list {
    let mut raw = ''
    try { raw = read_file(path) } catch e { return [[], []] }
    let lines = raw.split('\n')
    let mut names = []
    let mut values = []
    for line in lines {
        let trimmed = line.trim()
        if trimmed == '' { continue }
        let mut name = ''
        let mut value = 0.0
        if trimmed.contains('\'name\':\'') {
            let p = trimmed.split('\'name\':\'')
            if p.len() >= 2 { name = p[1].split('\'')[0] }
        }
        if trimmed.contains('\'value\':') {
            let p = trimmed.split('\'value\':')
            if p.len() >= 2 {
                let num_str = p[1].split(',')[0].split('}')[0].trim()
                value = to_float(num_str)
            }
        }
        if name != '' {
            names = names + [name]
            values = values + [value]
        }
    }
    [names, values]
}

let _home = exec('printenv HOME')
let _shared = _home + '/Dev/nexus/shared'
let log_path = _shared + '/discovery_log.jsonl'
let _n6 = load_jsonl(_shared + '/n6_constants.jsonl')
let _n6_names = _n6[0]
let _n6_values = _n6[1]
let _ph = load_jsonl(_shared + '/n6_physics.jsonl')
let _ph_names = _ph[0]
let _ph_values = _ph[1]

fn n6_match_name(value: float) -> string {
    // n6 상수 (절대 오차 < 0.0001)
    let mut i = 0
    while i < len(_n6_names) {
        if abs_f(value - _n6_values[i]) < 0.0001 {
            return _n6_names[i]
        }
        i = i + 1
    }
    // 물리 상수 (상대 오차 < 1%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.01 {
                return _ph_names[j]
            }
        }
        j = j + 1
    }
    ''
}

fn n6_match_grade(value: float) -> string {
    if n6_match_name(value) != '' {
        return 'EXACT'
    }
    // 물리 상수 NEAR (상대 오차 < 5%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.05 {
                return 'NEAR'
            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // 숫자 아닌 토큰 무시
        }
    }
    nums
}

fn record_discovery(value: float, name: string, grade: string, source: string) {
    let entry = '{\'constant\':\'' + name + '\',\'value\':\'' + to_string(value) + '\',\'grade\':\'' + grade + '\',\'source\':\'' + source + '\',\'processed\':true,\'alien_index\':{\'d\':0,\'r\':8},\'mk2\':{\'sector\':\'n6\',\'paths\':1}}'
    append_file(log_path, entry + '\n')
}

// ─── JSON에서 tool_response.stdout 추출 ───
fn extract_stdout(json_text: string) -> string {
    // 'tool_response':{'stdout':'...' 에서 stdout 값 추출
    if json_text.contains('\'stdout\':\'') {
        let parts = json_text.split('\'stdout\':\'')
        if parts.len() >= 2 {
            // 이스케이프된 따옴표를 넘겨서 진짜 닫는 따옴표 찾기
            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
    // JSON이 아니면 원본 그대로 (파이프 테스트 등)
    json_text
}

// ─── tool_input.command 추출 (소스 표시용) ───
fn extract_command(json_text: string) -> string {
    if json_text.contains('\'command\':\'') {
        let parts = json_text.split('\'command\':\'')
        if parts.len() >= 2 {
            let rest = parts[1]
            let end = rest.split('\'')[0]
            if end.len() > 40 { return end.split('')[0] + '...' }
            return end
        }
    }
    ''
}

// ─── CWD에서 프로젝트명 추출 ───
fn extract_project(json_text: string) -> string {
    if json_text.contains('\'cwd\':\'') {
        let parts = json_text.split('\'cwd\':\'')
        if parts.len() >= 2 {
            let cwd = parts[1].split('\'')[0]
            let segs = cwd.split('/')
            return segs[segs.len() - 1]
        }
    }
    'nexus'
}

