            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // 숫자 아닌 토큰 무시
        }
    }
    nums
}

