// self/runtime.c hexa_str_parse_int — auto-detect 0x/0X prefix:
HexaVal hexa_str_parse_int(HexaVal s) {
    if (!HX_IS_STR(s)) return hexa_int(0);
    const char* cs = HX_STR(s); const char* p = cs;
    if (*p == '+' || *p == '-') p++;
    int base = (p[0] == '0' && (p[1] == 'x' || p[1] == 'X')) ? 16 : 10;
    return hexa_int((int64_t)strtoll(cs, NULL, base));
}
// Same treatment in hexa_as_num string coercion path (TAG_STR + VALSTRUCT TAG_STR).
// Must NOT use base 0: that would parse '0777' as octal 511 instead of 777,
// breaking leading-zero decimal inputs.

