// Workaround — pow2(n) via * 2 / / 2 + disjoint-bit addition (no bit overlap).
// See self/runtime/bit_pure.hexa bit_shl_pure / self/runtime/bitops_pure.hexa bit_reverse32_pure.
fn pow2(n: int) -> int {
    let mut p = 1
    let mut i = 0
    while i < n { p = p * 2; i = i + 1 }
    return p
}
fn pack(r: int, x: int) -> int {
    return r * 2 + (x & 1)      // disjoint bits — addition == bitwise OR
}
fn half(x: int) -> int {
    return x / 2                // arithmetic right shift for non-negative ints
}

